prefix bbo: <http://www.onto-bpo.eu/ontologies/bbo#>
prefix bboExt: <http://www.onto-bpo.eu/ontologies/bboExtension#>
prefix rdfs: <http://www.w3.org/2000/01/rdf-schema#>
prefix tai: <https://www.teamingai-project.eu/>
prefix xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT ?task ?name ?taskId ?loopType ?isExecutable WHERE {
  ?task a bboExt:ChoreographyTask ;
        bbo:name ?name ;
        tai:belongsTo ?choreo .
  OPTIONAL { ?task bbo:id ?taskId . }
  OPTIONAL { ?task bboExt:loopType ?loopType . }
  OPTIONAL {
    ?task bboExt:isExecutable ?isExecutable .
  }
  ?choreo tai:belongsTo ?defs .
  ?defs tai:belongsTo ?model .
  ?model tai:originalId "2d225c9ff86b443c9f6bc6cfe687afbc" .
  FILTER(CONTAINS(LCASE(STR(?name)), LCASE("Probe aulsiefern")))
} 
LIMIT 25

prefix bbo: <http://www.onto-bpo.eu/ontologies/bbo#>
prefix bboExt: <http://www.onto-bpo.eu/ontologies/bboExtension#>
prefix rdfs: <http://www.w3.org/2000/01/rdf-schema#>
prefix tai: <https://www.teamingai-project.eu/>
prefix xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT ?elem ?name ?type ?taskId ?isExecutable ?loopType WHERE {
  ?elem a ?type ;
        bbo:name ?name ;
        tai:belongsTo ?choreo .
  OPTIONAL { ?elem bbo:id ?taskId . }
  OPTIONAL { ?elem bboExt:isExecutable ?isExecutable . }
  OPTIONAL { ?elem bboExt:loopType ?loopType . }

  ?choreo tai:belongsTo ?defs .
  ?defs tai:belongsTo ?model .
  ?model tai:originalId "2d225c9ff86b443c9f6bc6cfe687afbc" .

  FILTER(CONTAINS(LCASE(STR(?name)), LCASE("Probe aulsiefern")))
}
LIMIT 25

prefix bbo: <http://www.onto-bpo.eu/ontologies/bbo#>
prefix bboExt: <http://www.onto-bpo.eu/ontologies/bboExtension#>
prefix rdfs: <http://www.w3.org/2000/01/rdf-schema#>
prefix tai: <https://www.teamingai-project.eu/>
prefix xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT ?task ?name ?taskId WHERE {
  ?task a bboExt:ChoreographyTask ;
        bbo:name ?name ;
        tai:belongsTo ?choreo .
  ?choreo tai:belongsTo ?defs .
  ?defs tai:belongsTo ?model .
  ?model tai:originalId "2d225c9ff86b443c9f6bc6cfe687afbc" .
  FILTER( 
    CONTAINS(LCASE(STR(?name)), LCASE("probe")) ||
    CONTAINS(LCASE(STR(?name)), LCASE("aul")) ||
    CONTAINS(LCASE(STR(?name)), LCASE("sie"))
  )
  OPTIONAL { ?task bbo:id ?taskId . }
}
LIMIT 25

prefix bbo: <http://www.onto-bpo.eu/ontologies/bbo#>
prefix bboExt: <http://www.onto-bpo.eu/ontologies/bboExtension#>
prefix rdfs: <http://www.w3.org/2000/01/rdf-schema#>
prefix tai: <https://www.teamingai-project.eu/>
prefix xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT ?task ?taskName ?loopType ?hasOutgoing ?hasIncoming WHERE {
  {
    SELECT DISTINCT ?task ?taskName ?loopType WHERE {
      ?task a bboExt:ChoreographyTask ;
            bbo:name ?taskName ;
            tai:belongsTo ?choreo .
      ?choreo tai:belongsTo ?defs .
      ?defs tai:belongsTo ?model .
      ?model tai:originalId "2d225c9ff86b443c9f6bc6cfe687afbc" .
      FILTER(LCASE(STR(?taskName)) = LCASE("Probe ausliefern"))
      OPTIONAL { ?task bboExt:loopType ?loopType . }
    }
  }
  OPTIONAL {
    ?outEdge a bbo:SequenceFlow ;
             bbo:has_sourceRef ?task ;
             bbo:has_targetRef ?next .
  }
  BIND(BOUND(?next) AS ?hasOutgoing)
  OPTIONAL {
    ?inEdge a bbo:SequenceFlow ;
            bbo:has_targetRef ?task ;
            bbo:has_sourceRef ?prev .
  }
  BIND(BOUND(?prev) AS ?hasIncoming)
}
LIMIT 25
